class Solution:
    def numMagicSquaresInside(self, grid):
        rows = len(grid)
        cols = len(grid[0]) if rows else 0
        def is_magic(r, c):
            vals = []
            for i in range(3):
                for j in range(3):
                    vals.append(grid[r + i][c + j])
            if sorted(vals) != [1, 2, 3, 4, 5, 6, 7, 8, 9]:
                return False
            lines = []
            for i in range(3):
                lines.append(grid[r + i][c] + grid[r + i][c + 1] + grid[r + i][c + 2])
                lines.append(grid[r][c + i] + grid[r + 1][c + i] + grid[r + 2][c + i])
            lines.append(grid[r][c] + grid[r + 1][c + 1] + grid[r + 2][c + 2])
            lines.append(grid[r][c + 2] + grid[r + 1][c + 1] + grid[r + 2][c])
            return len(set(lines)) == 1
        count = 0
        for r in range(rows - 2):
            for c in range(cols - 2):
                if is_magic(r, c):
                    count += 1
        return count

