class Solution:
    def numMagicSquaresInside(self, grid):
        rows = len(grid)
        cols = len(grid[0]) if rows else 0
        def magic(r, c):
            seen = set()
            for i in range(3):
                for j in range(3):
                    v = grid[r + i][c + j]
                    if v < 1 or v > 9 or v in seen:
                        return False
                    seen.add(v)
            s = grid[r][c] + grid[r][c + 1] + grid[r][c + 2]
            for i in range(3):
                if grid[r + i][c] + grid[r + i][c + 1] + grid[r + i][c + 2] != s:
                    return False
                if grid[r][c + i] + grid[r + 1][c + i] + grid[r + 2][c + i] != s:
                    return False
            if grid[r][c] + grid[r + 1][c + 1] + grid[r + 2][c + 2] != s:
                return False
            if grid[r][c + 2] + grid[r + 1][c + 1] + grid[r + 2][c] != s:
                return False
            return True
        count = 0
        for r in range(rows - 2):
            for c in range(cols - 2):
                if magic(r, c):
                    count += 1
        return count

