var numMagicSquaresInside = function(grid) {
    const rows = grid.length;
    const cols = rows ? grid[0].length : 0;
    const magic = (r, c) => {
        const seen = new Set();
        for (let i = 0; i < 3; i++) {
            for (let j = 0; j < 3; j++) {
                const v = grid[r + i][c + j];
                if (v < 1 || v > 9 || seen.has(v)) return false;
                seen.add(v);
            }
        }
        const s = grid[r][c] + grid[r][c + 1] + grid[r][c + 2];
        for (let i = 0; i < 3; i++) {
            if (grid[r + i][c] + grid[r + i][c + 1] + grid[r + i][c + 2] !== s) return false;
            if (grid[r][c + i] + grid[r + 1][c + i] + grid[r + 2][c + i] !== s) return false;
        }
        if (grid[r][c] + grid[r + 1][c + 1] + grid[r + 2][c + 2] !== s) return false;
        if (grid[r][c + 2] + grid[r + 1][c + 1] + grid[r + 2][c] !== s) return false;
        return true;
    };
    let count = 0;
    for (let r = 0; r < rows - 2; r++) {
        for (let c = 0; c < cols - 2; c++) {
            if (magic(r, c)) count++;
        }
    }
    return count;
};
